import{_ as a,H as s,f as i,i as t}from"./chunks/framework.DbTCwA-u.js";const g=JSON.parse('{"title":"Animaux Holographiques","description":"Comment configurer les nametags des animaux dans pets.yml.","frontmatter":{"title":"Animaux Holographiques","description":"Comment configurer les nametags des animaux dans pets.yml."},"headers":[],"relativePath":"fr/config/pets.md","filePath":"fr/config/pets.md"}'),n={name:"fr/config/pets.md"};function l(r,e,o,u,p,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="animaux-holographiques-pets-yml" tabindex="-1">Animaux Holographiques (pets.yml) <a class="header-anchor" href="#animaux-holographiques-pets-yml" aria-label="Permalink to &quot;Animaux Holographiques (pets.yml)&quot;">​</a></h1><p>Le système d&#39;animaux est l&#39;une des fonctionnalités les plus innovantes d&#39;EligiusNametag. Avec cela, tout loup, perroquet ou chat apprivoisé par un joueur recevra un nametag holographique flottant qui suit l&#39;animal en douceur.</p><h3 id="configuration-de-base" tabindex="-1">Configuration de Base <a class="header-anchor" href="#configuration-de-base" aria-label="Permalink to &quot;Configuration de Base&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">pets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  show_unnamed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><ul><li>Si <code>show_unnamed</code> est <code>true</code>, même un loup apprivoisé générique aura un hologramme de texte.</li><li>Si réglé sur <code>false</code>, seuls les animaux que le joueur renomme en utilisant une <strong>Enclume</strong> (Name Tag vanilla) activeront le système holographique pour conserver un style plus Vanilla sur le serveur général.</li></ul><h3 id="design-des-lignes" tabindex="-1">Design des Lignes <a class="header-anchor" href="#design-des-lignes" aria-label="Permalink to &quot;Design des Lignes&quot;">​</a></h3><p>Utilisez <code>&lt;DISPLAYNAME&gt;</code> pour afficher le nom que le joueur lui a donné dans l&#39;enclume, et <code>&lt;PLAYER&gt;</code> pour citer le propriétaire.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  default_format</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;gray&gt;Animal de &lt;PLAYER&gt;&lt;/gray&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;white&gt;&lt;DISPLAYNAME&gt;&lt;/white&gt;&quot;</span></span></code></pre></div><h3 id="🐾-le-plus-grand-secret" tabindex="-1">🐾 Le Plus Grand Secret ! <a class="header-anchor" href="#🐾-le-plus-grand-secret" aria-label="Permalink to &quot;🐾 Le Plus Grand Secret !&quot;">​</a></h3><p>Les animaux <strong>héritent</strong> du design du rang Vault de leur propriétaire. Cela signifie que si le propriétaire d&#39;un chat a le rang &quot;Admin&quot; dans <code>players.yml</code>, et que le rang Admin a un texte rouge et une icône de feu, <strong>le chat montrera également le texte rouge et l&#39;icône de feu</strong> dans sa variable de groupe (si vous le configurez ainsi en croisant les variables PAPI ou les permissions LuckPerms au niveau du nœud <code>&lt;PLAYER&gt;</code>).</p>`,10)])])}const c=a(n,[["render",l]]);export{g as __pageData,c as default};
